mapper.update:
UPDATE fe_achievements
SET achievement_score = #{reachScore},
    updated_at   = NOW()
WHERE objective_id = #{objectiveId}
  AND user_id = #{userId}
  AND classroom_id = #{classroomId}
  AND course_id = #{courseId}

UPDATE fe_assessment_category_achievements
SET achievement_score = #{reachScore},
    updated_at   = NOW()
WHERE assessment_category_id = #{categoryId}
  AND user_id = #{userId}
  AND classroom_id = #{classroomId}
  AND course_id = #{courseId}

UPDATE cm_classroom_student
SET reach_state = #{reachState}
WHERE id = #{classroomStudentId}

mapper.delete:
DELETE FROM fe_achievements
WHERE user_id = #{userId}
  AND classroom_id = #{classroomId}

DELETE FROM fe_assessment_category_achievements
WHERE user_id = #{userId}
  AND classroom_id = #{classroomId}

mapper.select:
SELECT courseId
FROM cm_classroom
WHERE id = #{classroomId}

SELECT SUM(libStuScore) as stuScore, SUM(libScore) as fullScore
FROM ai_in_stu_ans_info
WHERE paperId = #{typeId}
  AND stuId = #{userId}

SELECT stuno
FROM sm_student
WHERE usersid = #{userId}

SELECT stu_score as stuScore, full_score as fullScore
FROM fe_external_assessment_task_detail
WHERE ex_assessment_task_id = #{typeId}
  AND stuno = #{stuNo}

SELECT score
FROM fe_objective_assessment_category
WHERE objective_id = #{objectiveId}
  AND category_id = #{categoryId}

SELECT COUNT(*)
FROM fe_achievements
WHERE user_id = #{userId}
  AND classroom_id = #{classroomId}
  AND objective_id = #{objectiveId}

SELECT COUNT(*)
FROM fe_assessment_category_achievements
WHERE user_id = #{userId}
  AND classroom_id = #{classroomId}
  AND assessment_category_id = #{categoryId}

SELECT userName
FROM cm_classroom_student
WHERE userId = #{userId}

SELECT userId
FROM cm_classroom_student
WHERE classroomId = #{classroomId}
